def load_ca():
    ca = pd.read_csv(OUT / "ca0030_clickstream_us_monthly_5y.csv")
    ca["date"] = pd.to_datetime(ca["date"]).dt.to_period("M").dt.to_timestamp()
    sum_s = ca.groupby("date")["website_users"].sum().sort_index().rename("ca")
    desk = ca[ca["platform_name"]=="Desktop Site"].set_index("date")["website_users"].sort_index().rename("ca")
    mob  = ca[ca["platform_name"]=="Mobile Site"].set_index("date")["website_users"].sort_index().rename("ca")
    return {"SUM": sum_s, "Desktop": desk, "Mobile": mob}


def load_macro(fname: str, name: str = None) -> pd.Series:
    """Load from outputs/fred/{fname}.json (existing or new format)."""
    p = FRED / f"{fname}.json"
    if not p.exists():
        raise FileNotFoundError(p)
    d = json.load(open(p))
    obs = pd.DataFrame(d["data"])
    obs["date"] = pd.to_datetime(obs["date"])
    obs["value"] = pd.to_numeric(obs["value"], errors="coerce")
    s = obs.set_index("date")["value"].sort_index()
    s.index = s.index.to_period("M").to_timestamp()
    s.name = name or fname
    return s


def macro_from_inline(name: str) -> pd.Series:
    info = MACROS_INLINE[name]
    df = pd.DataFrame(info["data"], columns=["date","value"])
    df["date"] = pd.to_datetime(df["date"]).dt.to_period("M").dt.to_timestamp()
    return df.set_index("date")["value"].sort_index().rename(name)


def yoy_corr(ca: pd.Series, macro: pd.Series, lags=range(-2,3)) -> dict:
    yc = ca.pct_change(12)
    ym = macro.pct_change(12)
    df = pd.concat([yc.rename("ca"), ym.rename("m")], axis=1, join="inner").dropna()
    out = {"n": len(df)}
    for k in lags:
        out[f"r{k:+d}"] = round(df["ca"].shift(k).corr(df["m"]), 3) if len(df)>=6 else None
    if len(df) >= 6:
        best_k = max(lags, key=lambda k: abs(out[f'r{k:+d}']))
        out["best_lag"] = best_k
        out["best_r"] = out[f"r{best_k:+d}"]
    return out


def main():
    ca_aggs = load_ca()

    # Macros: name → series
    macros = {}
    # Cached
    for fname, lbl in [("umich","UMich Sentiment"),
                       ("retail_sales","Retail Sales"),
                       ("nfp","NFP"),
                       ("core_cpi","Core CPI"),
                       ("pce_price","PCE Price (Fed pref)")]:
        try:
            macros[lbl] = load_macro(fname, lbl)
        except FileNotFoundError:
            print(f"missing cache: {fname}")
    # Inline new ones
    inline_labels = {
        "INDPRO":"Industrial Production","DGORDER":"Durable Goods Orders",
        "HOUST":"Housing Starts","HSN1F":"New Home Sales",
        "JTSQUL":"JOLTS Quits","PPIACO":"PPI (All Commodities)",
        "PI":"Personal Income (≈ Personal Spending proxy)",
        "CPIAUCSL":"CPI All Urban Consumers",
    }
    for k, lbl in inline_labels.items():
        macros[lbl] = macro_from_inline(k)

    rows = []
    for agg_name, ca_s in ca_aggs.items():
        for m_name, m_s in macros.items():
            r = yoy_corr(ca_s, m_s)
            rows.append({"ca_agg":agg_name,"macro":m_name,**r})

    df = pd.DataFrame(rows)
    df.to_csv(OUT/"ca0030_multi_macro_corr.csv", index=False)
    print(f"wrote {OUT/'ca0030_multi_macro_corr.csv'} ({len(df)} rows)")
    print()

    # Console pivot — SUM aggregation, best lag + best r
    sum_view = df[df["ca_agg"]=="SUM"].copy().sort_values("best_r", key=lambda s: s.abs(), ascending=False)
    print("CA0030 SUM × each macro, YoY %, best |r| (sorted):")
    print(sum_view[["macro","n","r-2","r-1","r+0","r+1","r+2","best_lag","best_r"]].to_string(index=False))

    # Direction breakdown: how many macros show CA leads (best_lag > 0) vs macro leads (best_lag < 0)?
    print()
    for agg_name in ["SUM","Desktop","Mobile"]:
        sub = df[df["ca_agg"]==agg_name]
        ca_leads = sub[sub["best_lag"]>0]
        macro_leads = sub[sub["best_lag"]<0]
        contemp = sub[sub["best_lag"]==0]
        print(f"\n{agg_name}: {len(sub)} macros — "
              f"CA leads (lag>0): {len(ca_leads)}, "
              f"contemp (lag=0): {len(contemp)}, "
              f"Macro leads (lag<0): {len(macro_leads)}")


if __name__ == "__main__":
    main()
